def solve(num: int):
if num == 0: return ''
    elif num < 20: return self.less_than_20[num] + ' '
    elif num < 100: return self.tens[num // 10] + ' ' + self.helper(num % 10)
    else: return self.less_than_20[num // 100] + ' Hundred ' + self.helper(num % 100)

